// UploadChunk implements mm_app.UploadService
func (mmUploadChunk *UploadServiceMock) UploadChunk(uploadID int64, chunkIndex int64, data []byte) (received int64, total int64, completed bool, missing []int64, err error) {
	mm_atomic.AddUint64(&mmUploadChunk.beforeUploadChunkCounter, 1)
	defer mm_atomic.AddUint64(&mmUploadChunk.afterUploadChunkCounter, 1)

	mmUploadChunk.t.Helper()

	if mmUploadChunk.inspectFuncUploadChunk != nil {
		mmUploadChunk.inspectFuncUploadChunk(uploadID, chunkIndex, data)
	}

	mm_params := UploadServiceMockUploadChunkParams{uploadID, chunkIndex, data}

	// Record call args
	mmUploadChunk.UploadChunkMock.mutex.Lock()
	mmUploadChunk.UploadChunkMock.callArgs = append(mmUploadChunk.UploadChunkMock.callArgs, &mm_params)
	mmUploadChunk.UploadChunkMock.mutex.Unlock()

	for _, e := range mmUploadChunk.UploadChunkMock.expectations {
		if minimock.Equal(*e.params, mm_params) {
			mm_atomic.AddUint64(&e.Counter, 1)
			return e.results.received, e.results.total, e.results.completed, e.results.missing, e.results.err
		}
	}

	if mmUploadChunk.UploadChunkMock.defaultExpectation != nil {
		mm_atomic.AddUint64(&mmUploadChunk.UploadChunkMock.defaultExpectation.Counter, 1)
		mm_want := mmUploadChunk.UploadChunkMock.defaultExpectation.params
		mm_want_ptrs := mmUploadChunk.UploadChunkMock.defaultExpectation.paramPtrs

		mm_got := UploadServiceMockUploadChunkParams{uploadID, chunkIndex, data}

		if mm_want_ptrs != nil {

			if mm_want_ptrs.uploadID != nil && !minimock.Equal(*mm_want_ptrs.uploadID, mm_got.uploadID) {
				mmUploadChunk.t.Errorf("UploadServiceMock.UploadChunk got unexpected parameter uploadID, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
					mmUploadChunk.UploadChunkMock.defaultExpectation.expectationOrigins.originUploadID, *mm_want_ptrs.uploadID, mm_got.uploadID, minimock.Diff(*mm_want_ptrs.uploadID, mm_got.uploadID))
			}

			if mm_want_ptrs.chunkIndex != nil && !minimock.Equal(*mm_want_ptrs.chunkIndex, mm_got.chunkIndex) {
				mmUploadChunk.t.Errorf("UploadServiceMock.UploadChunk got unexpected parameter chunkIndex, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
					mmUploadChunk.UploadChunkMock.defaultExpectation.expectationOrigins.originChunkIndex, *mm_want_ptrs.chunkIndex, mm_got.chunkIndex, minimock.Diff(*mm_want_ptrs.chunkIndex, mm_got.chunkIndex))
			}

			if mm_want_ptrs.data != nil && !minimock.Equal(*mm_want_ptrs.data, mm_got.data) {
				mmUploadChunk.t.Errorf("UploadServiceMock.UploadChunk got unexpected parameter data, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
					mmUploadChunk.UploadChunkMock.defaultExpectation.expectationOrigins.originData, *mm_want_ptrs.data, mm_got.data, minimock.Diff(*mm_want_ptrs.data, mm_got.data))
			}

		} else if mm_want != nil && !minimock.Equal(*mm_want, mm_got) {
			mmUploadChunk.t.Errorf("UploadServiceMock.UploadChunk got unexpected parameters, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
				mmUploadChunk.UploadChunkMock.defaultExpectation.expectationOrigins.origin, *mm_want, mm_got, minimock.Diff(*mm_want, mm_got))
		}

		mm_results := mmUploadChunk.UploadChunkMock.defaultExpectation.results
		if mm_results == nil {
			mmUploadChunk.t.Fatal("No results are set for the UploadServiceMock.UploadChunk")
		}
		return (*mm_results).received, (*mm_results).total, (*mm_results).completed, (*mm_results).missing, (*mm_results).err
	}
	if mmUploadChunk.funcUploadChunk != nil {
		return mmUploadChunk.funcUploadChunk(uploadID, chunkIndex, data)
	}
	mmUploadChunk.t.Fatalf("Unexpected call to UploadServiceMock.UploadChunk. %v %v %v", uploadID, chunkIndex, data)
	return
}

